Code.Terraform:
```hcl
# 特定のプリンシパルにSQSポリシーを制限する（公開しない）
resource "aws_sqs_queue_policy" "<example_resource_name>" {
  queue_url = "<example_queue_url>"
  policy    = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Principal = { AWS = "<example_account_id>" } # 重大: 特定のプリンシパルに制限する（公開の「*」を削除）
      Action    = "sqs:*"
      Resource  = "<example_queue_arn>"
    }]
  })
}
```
